(function(){
  if(!window.jspdf||!window.jspdf.jsPDF){return;}
  var API=window.jspdf.jsPDF.API;
  function reg(vfs,b64,family,style){
    API.events.push(['addFonts', function(){ this.addFileToVFS(vfs,b64); this.addFont(vfs,family,style); }]);
  }
  reg('LexendExa-normal.ttf','','LexendExa','normal');
  reg('LexendExa-bold.ttf','','LexendExa','bold');
  reg('GreatVibes-normal.ttf','','GreatVibes','normal');
})();